/* Better Dashboard Styles - Focused on Bot Pool Management */

:root {
  --primary: #00d4ff;
  --success: #28a745;
  --warning: #ffc107;
  --danger: #dc3545;
  --info: #17a2b8;
}

[data-theme="dark"] {
  --bg-primary: #0a0a0a;
  --bg-secondary: #1a1a1a;
  --bg-tertiary: #2a2a2a;
  --text-primary: #ffffff;
  --text-secondary: #b0b0b0;
  --border: #333333;
}

[data-theme="light"] {
  --bg-primary: #ffffff;
  --bg-secondary: #f8f9fa;
  --bg-tertiary: #e9ecef;
  --text-primary: #212529;
  --text-secondary: #6c757d;
  --border: #dee2e6;
}

/* Monitor Section */
.monitor-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 2rem;
  padding: 1.5rem;
  background: var(--bg-secondary);
  border-radius: 10px;
}

.monitor-controls {
  display: flex;
  gap: 2rem;
  align-items: center;
}

.bot-selector {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.bot-selector label {
  font-weight: 600;
  color: var(--text-secondary);
}

.bot-count-select {
  padding: 0.75rem 1.5rem;
  font-size: 1.1rem;
  background: var(--bg-tertiary);
  color: var(--text-primary);
  border: 2px solid var(--primary);
  border-radius: 8px;
  cursor: pointer;
  min-width: 180px;
}

.bot-count-select:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.adjusting {
  color: var(--warning);
  font-size: 0.9rem;
  animation: pulse 1s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

.status-indicator {
  padding: 0.5rem 1rem;
  border-radius: 8px;
  background: var(--bg-tertiary);
}

.status-ok {
  color: var(--success);
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.status-adjusting {
  color: var(--warning);
  display: flex;
  align-items: center;

